// Unless required by applicable law or agreed to in writing, software
// distributed under the License is distributed on an "AS IS" BASIS,
// WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.
// See the License for the specific language governing permissions and
// limitations under the License.

package store

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"strconv"
	"strings"
	"time"

	"github.com/redis/go-redis/v9"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/common/types"
)

type RedisStore struct {
	client *redis.Client
}

func NewRedisStore() (*RedisStore, error) {
	addr := os.Getenv("REDIS_ADDR")
	if addr == "" {
		return nil, errors.New("REDIS_ADDR environment variable is not set")
	}

	password := os.Getenv("REDIS_PASSWORD")
	passwordRequired := true
	if val := os.Getenv("REDIS_PASSWORD_REQUIRED"); val != "" {
		passwordRequired = strings.ToLower(val) != "false"
	}

	if password == "" && passwordRequired {
		return nil, errors.New("REDIS_PASSWORD is required (set REDIS_PASSWORD_REQUIRED=false to disable)")
	}

	client := redis.NewClient(&redis.Options{
		Addr:     addr,
		Password: password,
	})

	return &RedisStore{
		client: client,
	}, nil
}

func (r *RedisStore) Ping(ctx context.Context) error {
	pong, err := r.client.Ping(ctx).Result()
	if err != nil {
		return err
	}
	if pong != "PONG" {
		return fmt.Errorf("unexpected ping response: %s", pong)
	}
	return nil
}

func (r *RedisStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := sessionKey(sessionID)
	data, err := r.client.Get(ctx, key).Bytes()
	if err != nil {
		if errors.Is(err, redis.Nil) {
			return nil, ErrNotFound
		}
		return nil, err
	}

	var sandbox types.SandboxInfo
	if err := json.Unmarshal(data, &sandbox); err != nil {
		return nil, err
	}

	return &sandbox, nil
}

func (r *RedisStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return errors.New("sandbox cannot be nil")
	}
	if sandbox.ExpiresAt.IsZero() {
		return errors.New("sandbox expiresAt cannot be zero")
	}

	key := sessionKey(sandbox.SessionID)
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	pipe := r.client.Pipeline()

	setCmd := pipe.SetNX(ctx, key, data, 0)
	expiryCmd := pipe.ZAdd(ctx, ExpiryIndexKey, redis.Z{
		Score:  float64(sandbox.ExpiresAt.Unix()),
		Member: sandbox.SessionID,
	})
	activityCmd := pipe.ZAdd(ctx, LastActivityIndexKey, redis.Z{
		Score:  float64(time.Now().Unix()),
		Member: sandbox.SessionID,
	})

	cmds, err := pipe.Exec(ctx)
	if err != nil {
		return err
	}

	if !setCmd.Val() {
		return errors.New("session already exists")
	}

	if err := expiryCmd.Err(); err != nil {
		return err
	}

	if err := activityCmd.Err(); err != nil {
		return err
	}

	klog.V(4).Infof("Stored sandbox for session %s", sandbox.SessionID)
	return nil
}

func (r *RedisStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return errors.New("sandbox cannot be nil")
	}

	key := sessionKey(sandbox.SessionID)
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	setXX := r.client.Set(ctx, key, data, 0)
	ok, err := setXX.Result()
	if err != nil {
		return err
	}
	if !ok {
		return errors.New("key not exists")
	}

	klog.V(4).Infof("Updated sandbox for session %s", sandbox.SessionID)
	return nil
}

func (r *RedisStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := sessionKey(sessionID)

	pipe := r.client.Pipeline()
	delCmd := pipe.Del(ctx, key)
	zremExpiry := pipe.ZRem(ctx, ExpiryIndexKey, sessionID)
	zremActivity := pipe.ZRem(ctx, LastActivityIndexKey, sessionID)

	_, err := pipe.Exec(ctx)
	if err != nil {
		return err
	}

	if delCmd.Val() == 0 {
		return ErrNotFound
	}

	if err := zremExpiry.Err(); err != nil {
		return err
	}
	if err := zremActivity.Err(); err != nil {
		return err
	}

	klog.V(4).Infof("Deleted sandbox for session %s", sessionID)
	return nil
}

func (r *RedisStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return []*types.SandboxInfo{}, nil
	}

	sessionIDs, err := r.client.ZRangeByScore(ctx, ExpiryIndexKey, &redis.ZRangeBy{
		Min: "-inf",
		Max: strconv.FormatInt(before.Unix(), 10),
		Offset: 0,
		Count:  int64(limit),
	}).Result()
	if err != nil {
		return nil, err
	}

	return r.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (r *RedisStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return []*types.SandboxInfo{}, nil
	}

	sessionIDs, err := r.client.ZRangeByScore(ctx, LastActivityIndexKey, &redis.ZRangeBy{
		Min: "-inf",
		Max: strconv.FormatInt(before.Unix(), 10),
		Offset: 0,
		Count:  int64(limit),
	}).Result()
	if err != nil {
		return nil, err
	}

	return r.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (r *RedisStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return []*types.SandboxInfo{}, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, sid := range sessionIDs {
		keys[i] = sessionKey(sid)
	}

	cmds, err := r.client.MGet(ctx, keys...).Result()
	if err != nil {
		return nil, err
	}

	sandboxes := make([]*types.SandboxInfo, 0, len(sessionIDs))
	for i, cmd := range cmds {
		if cmd == nil {
			klog.V(4).Infof("Skipping orphan session ID: %s", sessionIDs[i])
			continue
		}

		data, ok := cmd.(string)
		if !ok {
			klog.V(4).Infof("Skipping invalid data for session ID: %s", sessionIDs[i])
			continue
		}

		var sandbox types.SandboxInfo
		if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
			klog.V(4).Infof("Skipping unmarshalable data for session ID: %s", sessionIDs[i])
			continue
		}

		sandboxes = append(sandboxes, &sandbox)
	}

	return sandboxes, nil
}

func (r *RedisStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return errors.New("sessionID cannot be empty")
	}

	if at.IsZero() {
		at = time.Now()
	}

	key := sessionKey(sessionID)
	exists, err := r.client.Exists(ctx, key).Result()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	err = r.client.ZAdd(ctx, LastActivityIndexKey, redis.Z{
		Score:  float64(at.Unix()),
		Member: sessionID,
	}).Err()
	if err != nil {
		return err
	}

	klog.V(4).Infof("Updated last activity for session %s", sessionID)
	return nil
}

func (r *RedisStore) Close() {
	if r.client != nil {
		if err := r.client.Close(); err != nil {
			klog.Errorf("Failed to close Redis client: %v", err)
		}
	}
}

