	if err != nil {
		return err
	}

	pipe := v.client.B().Pipeline()

	setnx := pipe.Setnx().Key(key).Value(string(data)).Build()
	zaddExpiry := pipe.Zadd().Key(ExpiryIndexKey).Member(valkey.Z{
		Score:  float64(sandbox.ExpiresAt.Unix()),
		Member: sandbox.SessionID,
	}).Build()
	zaddActivity := pipe.Zadd().Key(LastActivityIndexKey).Member(valkey.Z{
		Score:  float64(time.Now().Unix()),
		Member: sandbox.SessionID,
	}).Build()

	results, err := v.client.DoMulti(ctx, setnx, zaddExpiry, zaddActivity)
	if err != nil {
		return err
	}

	setnxResult, err := results[0].AsInt64()
	if err != nil {
		return err
	}
	if setnxResult == 0 {
